import React, { useState } from 'react';
import Review from './Review';
import ReviewForm from './ReviewForm';

function BookDetails({ book, onBack, onUpdateBook }) {
  const [showReviewForm, setShowReviewForm] = useState(false);

  const handleAddReview = (reviewData) => {
    const newReview = {
      id: Date.now(),
      ...reviewData,
      date: new Date().toLocaleDateString()
    };

    const updatedBook = {
      ...book,
      reviews: [...book.reviews, newReview]
    };

    // Recalculate average rating
    const totalRating = updatedBook.reviews.reduce((sum, review) => sum + review.rating, 0);
    updatedBook.rating = totalRating / updatedBook.reviews.length;

    onUpdateBook(updatedBook);
    setShowReviewForm(false);
  };

  const handleUpdateReview = (reviewId, updatedReviewData) => {
    const updatedReviews = book.reviews.map(review => 
      review.id === reviewId 
        ? { ...review, ...updatedReviewData }
        : review
    );

    const updatedBook = {
      ...book,
      reviews: updatedReviews
    };

    // Recalculate average rating
    const totalRating = updatedBook.reviews.reduce((sum, review) => sum + review.rating, 0);
    updatedBook.rating = totalRating / updatedBook.reviews.length;

    onUpdateBook(updatedBook);
  };

  const handleDeleteReview = (reviewId) => {
    const updatedReviews = book.reviews.filter(review => review.id !== reviewId);

    const updatedBook = {
      ...book,
      reviews: updatedReviews
    };

    // Recalculate average rating
    if (updatedBook.reviews.length > 0) {
      const totalRating = updatedBook.reviews.reduce((sum, review) => sum + review.rating, 0);
      updatedBook.rating = totalRating / updatedBook.reviews.length;
    } else {
      updatedBook.rating = 0;
    }

    onUpdateBook(updatedBook);
  };

  return (
    <div className="animate-fade-in">
      {/* Navigation */}
      <div className="mb-8">
        <button
          onClick={onBack}
          className="btn btn-secondary group"
        >
          <svg className="icon-sm mr-2 transform group-hover:-translate-x-1 transition-transform duration-200" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Back to Library
        </button>
      </div>

      {/* Book Header */}
      <div className="card mb-8 animate-fade-in-up">
        <div className="card-body">
          <div className="flex flex-col lg:flex-row lg:items-start gap-8">
            {/* Book Cover */}
            <div className="flex-shrink-0">
              <div className="w-48 h-72 bg-gradient-primary rounded-2xl shadow-lg flex items-center justify-center mx-auto lg:mx-0">
                <span className="text-6xl text-white opacity-90">📖</span>
              </div>
            </div>

            {/* Book Info */}
            <div className="flex-1 text-center lg:text-left">
              <h1 className="text-4xl lg:text-5xl font-bold text-primary mb-4">
                {book.title}
              </h1>
              <p className="text-xl text-secondary mb-6">
                by <span className="font-semibold text-primary">{book.author}</span>
              </p>

              {/* Rating Display */}
              <div className="flex items-center justify-center lg:justify-start gap-4 mb-6">
                <div className="flex items-center">
                  {[...Array(5)].map((_, i) => (
                    <span
                      key={i}
                      className={`text-2xl ${
                        i < Math.floor(book.rating) ? 'text-warning' : 'text-muted'
                      }`}
                    >
                      ★
                    </span>
                  ))}
                </div>
                <span className="text-2xl font-bold text-primary">
                  {book.rating.toFixed(1)}
                </span>
                <span className="text-secondary">
                  ({book.reviews.length} review{book.reviews.length !== 1 ? 's' : ''})
                </span>
              </div>

              {/* Description */}
              {book.description && (
                <div className="mb-6">
                  <h3 className="text-lg font-semibold text-primary mb-3">Description</h3>
                  <p className="text-secondary leading-relaxed">{book.description}</p>
                </div>
              )}

              {/* Add Review Button */}
              <button
                onClick={() => setShowReviewForm(true)}
                className="btn btn-primary"
              >
                <svg className="icon-sm mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6" />
                </svg>
                Write a Review
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Review Form */}
      {showReviewForm && (
        <div className="mb-8 animate-fade-in-up">
          <ReviewForm
            onSubmit={handleAddReview}
            onCancel={() => setShowReviewForm(false)}
          />
        </div>
      )}

      {/* Reviews Section */}
      <div className="card animate-fade-in-up animate-delay-200">
        <div className="card-header">
          <div className="flex items-center justify-between">
            <h2 className="text-2xl font-bold text-primary">Reviews</h2>
            <div className="text-sm text-muted">
              {book.reviews.length} review{book.reviews.length !== 1 ? 's' : ''}
            </div>
          </div>
        </div>

        <div className="card-body">
          {book.reviews.length === 0 ? (
            <div className="text-center py-12">
              <div className="text-4xl mb-4 opacity-50">💭</div>
              <h3 className="text-xl font-semibold text-primary mb-2">No reviews yet</h3>
              <p className="text-secondary mb-6">Be the first to share your thoughts about this book!</p>
              <button
                onClick={() => setShowReviewForm(true)}
                className="btn btn-primary"
              >
                Write First Review
              </button>
            </div>
          ) : (
            <div className="space-y-6">
              {book.reviews.map((review, index) => (
                <div
                  key={review.id}
                  className="animate-fade-in-up"
                  style={{ animationDelay: `${index * 100}ms` }}
                >
                  <Review
                    review={review}
                    onUpdate={(updatedReview) => handleUpdateReview(review.id, updatedReview)}
                    onDelete={() => handleDeleteReview(review.id)}
                  />
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default BookDetails;
